prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?mfName ?srcRef ?tgtRef ?msgRef ?msgName WHERE {
  ?choreo a bboExt:Choreography .
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-4F47FE5C-11B4-459C-BF80-F9D6BB03E80C> tai:belongsTo ?choreo .
  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .
  {
    ?mf bboExt:sourceRef ?srcRef .
    FILTER(CONTAINS("sid-4F47FE5C-11B4-459C-BF80-F9D6BB03E80C", ?srcRef) || CONTAINS(?srcRef, "4F47FE5C"))
  } UNION {
    ?mf bboExt:targetRef ?tgtRef .
    FILTER(CONTAINS("sid-4F47FE5C-11B4-459C-BF80-F9D6BB03E80C", ?tgtRef) || CONTAINS(?tgtRef, "4F47FE5C"))
  }
  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:sourceRef ?srcRef . }
  OPTIONAL { ?mf bboExt:targetRef ?tgtRef . }
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }
  OPTIONAL {
    ?msg a bboExt:Message .
    ?msg tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?msg), ?msgRef))
    ?msg bbo:name ?msgName .
  }
}
LIMIT 25

